#### Implementation (promise/promise.go:24-71)
```go
type promise struct {
    doneCtx context.Context
    doneVal interface{}
    setCh   chan struct{}
    onceler sync.Once
    value   interface{}
}

func NewWriteOnce(initial interface{}, doneCtx context.Context, doneVal interface{}) WriteOnce {
    p := &promise{
        doneCtx: doneCtx,
        doneVal: doneVal,
        setCh:   make(chan struct{}),
    }
    if initial != nil {
        p.Set(initial)
    }
    return p
}

func (p *promise) Get() interface{} {
    select {
    case <-p.setCh:
    case <-p.doneCtx.Done():
        p.Set(p.doneVal)  // Auto-cancel on context done
    }
    return p.value
}

func (p *promise) Set(value interface{}) bool {
    var ans bool
    p.onceler.Do(func() {
        p.value = value
        close(p.setCh)
        ans = true
    })
    return ans
}
```

